        modelBuilder.Entity<Blog>(entity =>
        {
            // Preserve the old discriminator property name for existing documents
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve the old compound id format ("Blog|1") for existing documents
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
